function automatic integer recurse;
    input integer base, width, rt;
    recurse = base == 1 ? rt : recurse(base / width, width, rt);
endfunction
localparam P = recurse(5, 0, 0);

function automatic integer iter;
    input integer b, w, r;
    iter = b == 1 ? r : iter(b / w, w, r + 1);
endfunction
localparam SIZE = iter(5, 0, 0);

function automatic integer f;
    input integer base, lut_width, rt;
    f = base == 1 ? rt : f(base / lut_width + (base / lut_width * lut_width == base ? 0 : 1), lut_width, rt);
endfunction
